+    #[test]
+    fn histogram_stats_debug_clone_serde() {
+        let s = HistogramStats {
+            count: 100,
+            sum: 5000.0,
+            mean: Some(50.0),
+            min: Some(1.0),
+            max: Some(1000.0),
+            p50: Some(32.0),
+            p90: Some(512.0),
+            p99: Some(1024.0),
